// GetRunGraphQL implements RunsStateProvider.
func (s *ServerState) GetRunGraphQL(id string) (*ddxgraphql.Run, bool) {
	if id == "" {
		return nil, false
	}
	// Search all projects.
	for _, proj := range s.GetProjects(false) {
		runs := s.loadRunsForProject(proj.ID, proj.Path)
		for _, r := range runs {
			if r.ID == id {
				s.loadRunDetail(r)
				return r, true
			}
		}
	}
	return nil, false
}

